import{_ as a,c as t,o as i,a2 as o}from"./chunks/framework.CIiVzG-O.js";const r="/pets/ragdoll_500.png",l="/pets/british_500.png",n="/pets/shibainu_500.png",s="/pets/corgi_500.png",u="/pets/husky_500.png",h="/pets/tugou_500.png",P=JSON.parse('{"title":"Premium Pets","description":"","frontmatter":{},"headers":[],"relativePath":"guide/pets.md","filePath":"guide/pets.md","lastUpdated":1781426591000}'),d={name:"guide/pets.md"};function p(c,e,m,g,b,f){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="premium-pets" tabindex="-1">Premium Pets <a class="header-anchor" href="#premium-pets" aria-label="Permalink to &quot;Premium Pets&quot;">​</a></h1><p>PetReminder comes with a free default pet, and you can unlock more adorable breeds through in-app purchase (IAP). Each premium pet has unique animations, behaviors, and personality.</p><h2 id="free-pet" tabindex="-1">Free Pet <a class="header-anchor" href="#free-pet" aria-label="Permalink to &quot;Free Pet&quot;">​</a></h2><p>The base app includes a cute default pet cat (Tugou) that will keep you company. It&#39;s completely free — no purchase needed.</p><h2 id="premium-pets-1" tabindex="-1">Premium Pets <a class="header-anchor" href="#premium-pets-1" aria-label="Permalink to &quot;Premium Pets&quot;">​</a></h2><h3 id="ragdoll-cat" tabindex="-1">Ragdoll Cat <a class="header-anchor" href="#ragdoll-cat" aria-label="Permalink to &quot;Ragdoll Cat&quot;">​</a></h3><p><strong>¥18</strong></p><p><img src="'+r+'" alt="Ragdoll Cat"></p><p>Elegant and graceful, the Ragdoll Cat has a calm temperament and loves to lounge around. Its unique animations and gentle sounds make every reminder a pleasant moment.</p><ul><li>Unique animations: stretching, rolling, pawing</li><li>Gentle meowing sounds</li><li>Elegant coat pattern</li></ul><h3 id="british-shorthair-cat" tabindex="-1">British Shorthair Cat <a class="header-anchor" href="#british-shorthair-cat" aria-label="Permalink to &quot;British Shorthair Cat&quot;">​</a></h3><p><strong>¥12</strong></p><p><img src="'+l+'" alt="British Shorthair"></p><p>Chubby and adorable, the British Shorthair is the perfect cuddly companion. Its round face and plush body will warm your heart every day.</p><ul><li>Unique animations: sitting ball, head tilt, lazy yawn</li><li>Soft purring sounds</li><li>Distinctive round face with big eyes</li></ul><h3 id="shiba-inu" tabindex="-1">Shiba Inu <a class="header-anchor" href="#shiba-inu" aria-label="Permalink to &quot;Shiba Inu&quot;">​</a></h3><p><strong>¥299</strong></p><p><img src="'+n+'" alt="Shiba Inu"></p><p>Playful and lively, the Shiba Inu brings energy to your desktop. Full of personality and charm, it&#39;s always ready to brighten your day.</p><ul><li>Unique animations: zoomies, head tilt, playful bark</li><li>Energetic sound effects</li><li>Expressive face with iconic Shiba smile</li></ul><h3 id="corgi" tabindex="-1">Corgi <a class="header-anchor" href="#corgi" aria-label="Permalink to &quot;Corgi&quot;">​</a></h3><p><strong>¥299</strong></p><p><img src="'+s+'" alt="Corgi"></p><p>Energetic with short little legs, the Corgi is pure joy in a small package. Watch its stubby legs waddle across your screen!</p><ul><li>Unique animations: sploot, waddle run, tail wag</li><li>Cheerful barking sounds</li><li>Adorable short legs and fluffy bottom</li></ul><h3 id="husky" tabindex="-1">Husky <a class="header-anchor" href="#husky" aria-label="Permalink to &quot;Husky&quot;">​</a></h3><p><strong>¥399</strong></p><p><img src="'+u+'" alt="Husky"></p><p>Expressive and handsome, the Husky brings the drama. Known for its &quot;talking&quot; behavior, this breed will make you smile with its quirky personality.</p><ul><li>Unique animations: howling, talking, dramatic flop</li><li>Vocal sound effects (Husky &quot;talking&quot;)</li><li>Stunning coat and striking blue eyes</li></ul><h3 id="tugou-free" tabindex="-1">Tugou (Free) <a class="header-anchor" href="#tugou-free" aria-label="Permalink to &quot;Tugou (Free)&quot;">​</a></h3><p><img src="'+h+'" alt="Tugou"></p><p>Loyal and spirited, Tugou is the free default pet that comes with PetReminder. A faithful companion that&#39;s always ready to keep you company.</p><ul><li>Unique animations: tail wag, happy jump, head tilt</li><li>Friendly bark sounds</li><li>Loyal and affectionate personality</li></ul><h2 id="bundles" tabindex="-1">Bundles <a class="header-anchor" href="#bundles" aria-label="Permalink to &quot;Bundles&quot;">​</a></h2><h3 id="🐱-full-cat-bundle" tabindex="-1">🐱 Full Cat Bundle <a class="header-anchor" href="#🐱-full-cat-bundle" aria-label="Permalink to &quot;🐱 Full Cat Bundle&quot;">​</a></h3><p><strong>¥25</strong> (Save ¥5)</p><p>Unlock both <strong>Ragdoll Cat</strong> + <strong>British Shorthair Cat</strong> at a discounted price. Perfect for cat lovers who want both!</p><h2 id="how-to-purchase" tabindex="-1">How to Purchase <a class="header-anchor" href="#how-to-purchase" aria-label="Permalink to &quot;How to Purchase&quot;">​</a></h2><ol><li>Open PetReminder</li><li>Go to the <strong>Pets</strong> tab</li><li>Browse available pets and tap <strong>Purchase</strong> on any premium pet</li><li>Confirm the in-app purchase</li><li>The pet will be unlocked and ready to use immediately</li></ol><h3 id="restore-purchases" tabindex="-1">Restore Purchases <a class="header-anchor" href="#restore-purchases" aria-label="Permalink to &quot;Restore Purchases&quot;">​</a></h3><p>If you&#39;ve purchased pets on a different device or after reinstalling:</p><ol><li>Open PetReminder → <strong>Pets</strong> tab</li><li>Tap <strong>Restore Purchases</strong></li><li>Your previously purchased pets will be restored</li></ol><h2 id="download-storage" tabindex="-1">Download &amp; Storage <a class="header-anchor" href="#download-storage" aria-label="Permalink to &quot;Download &amp; Storage&quot;">​</a></h2><p>Premium pet files (<code>.catpet</code>) are downloaded directly through the Mac App Store. Once downloaded, they are stored locally on your Mac — no internet connection needed for the pet to appear.</p><h2 id="more-coming-soon" tabindex="-1">More Coming Soon <a class="header-anchor" href="#more-coming-soon" aria-label="Permalink to &quot;More Coming Soon&quot;">​</a></h2><p>We&#39;re constantly working on new pet breeds, including more cats, dogs, and maybe even some surprise animals! Stay tuned for updates.</p>',47)])])}const k=a(d,[["render",p]]);export{P as __pageData,k as default};
